body.script:
                    let barcode = "";
                    let timeout;

                    // التقاط أي كتابة (من قارئ الباركود)
                    document.addEventListener('keydown', function(e) {
                        if (e.key === 'Enter') {
                            if (barcode.length > 2) {
                                fetchPrice(barcode);
                            }
                            barcode = "";
                        } else if (e.key.length === 1) {
                            barcode += e.key;
                        }
                    });

                    async function fetchPrice(scannedBarcode) {
                        try {
                            const response = await fetch('/price-checker/scan', {
                                method: 'POST',
                                headers: {
                                    'Content-Type': 'application/json',
                                },
                                body: JSON.stringify({
                                    jsonrpc: "2.0",
                                    method: "call",
                                    params: { barcode: scannedBarcode }
                                })
                            });
                            
                            const data = await response.json();
                            const result = data.result;

                            // إخفاء شاشة الانتظار وإظهار النتيجة
                            document.getElementById('idle-screen').style.display = 'none';
                            const resultScreen = document.getElementById('result-screen');
                            resultScreen.style.display = 'block';

                            if (result.found) {
                                document.getElementById('p-image').src = result.image_url;
                                document.getElementById('p-image').style.display = 'block';
                                document.getElementById('p-name').textContent = result.name;
                                document.getElementById('p-price').textContent = result.price;
                            } else {
                                document.getElementById('p-image').style.display = 'none';
                                document.getElementById('p-name').textContent = "المنتج غير مسجل";
                                document.getElementById('p-price').textContent = "برجاء مراجعة خدمة العملاء";
                            }

                            // إعادة الشاشة لوضع الانتظار بعد 8 ثوانٍ
                            clearTimeout(timeout);
                            timeout = setTimeout(() => {
                                resultScreen.style.display = 'none';
                                document.getElementById('idle-screen').style.display = 'block';
                            }, 8000);

                        } catch (error) {
                            console.error("Error fetching price:", error);
                        }
                    }
